package main

import (
	"context"
	"fmt"
	"time"

	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	for _, item := range items {
		vm := otto.New()
		// Create an interrupt channel for the VM
		interrupt := make(chan func(), 1)
		vm.Interrupt = interrupt

		// Inject the current item as a global variable named 'item'
		err := vm.Set("item", item)
		if err != nil {
			return nil, err
		}

		// Create a channel to wait for the script to finish
		done := make(chan error, 1)
		var value otto.Value

		// Run the script in a goroutine
		go func() {
			v, err := vm.Run(conditionScript)
			value = v
			done <- err
		}()

		// Create a context with a timeout of 100 milliseconds
		ctx, cancel := context.WithTimeout(context.Background(), 100*time.Millisecond)
		defer cancel()

		select {
		case err := <-done:
			// The script finished before the timeout
			if err != nil {
				return nil, err
			}
		case <-ctx.Done():
			// Timeout occurred
			// Try to send an interrupt function to the VM
			select {
			case interrupt <- func() {
				panic("interrupt")
			}:
				// The interrupt was sent, now wait for the script to stop
				err := <-done
				if err != nil {
					// Check if it's an interrupt error
					if e, ok := err.(*otto.Error); ok && e.Error() == "interrupt" {
						return nil, fmt.Errorf("script execution timed out")
					}
					return nil, err
				}
				// The script finished without error after the interrupt was sent?
				// This should not happen because the interrupt causes a panic. But if it does, we treat it as timeout.
				return nil, fmt.Errorf("script execution timed out")
			default:
				// The interrupt channel was not ready? This should not happen because we have a buffer of 1.
				// Check if the script finished in the meantime.
				select {
				case err := <-done:
					if err != nil {
						return nil, err
					}
					// The script finished, but we are in the timeout case? We still consider it a timeout because the context expired.
					return nil, fmt.Errorf("script execution timed out")
				default:
					// The script is still running and we couldn't send the interrupt? Return timeout.
					return nil, fmt.Errorf("script execution timed out")
				}
			}
		}

		// Convert the result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

